// Parse AI response and add to job data
const aiResponse = $json.output;
let parsed;

try {
  // Extract JSON from response
  const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[0]);
  } else {
    // Fallback if AI didn't return JSON
    parsed = {
      match_score: 50,
      confidence: 'low',
      reasoning: 'Failed to parse AI response',
      matched_skills: [],
      missing_skills: [],
      recommendation: 'skip'
    };
  }
} catch (error) {
  parsed = {
    match_score: 50,
    confidence: 'low',
    reasoning: 'Error parsing response',
    matched_skills: [],
    missing_skills: [],
    recommendation: 'skip'
  };
}

// Merge with original job data
return [{
  json: {
    ...$('Split Into Items').item.json,
    ai_evaluation: parsed
  }
}];

