// Create HTML email digest
const jobs = $input.all();
const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

const html = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; padding: 20px; background: #f5f5f5; }
    .container { max-width: 800px; margin: 0 auto; background: white; padding: 30px; border-radius: 10px; }
    h1 { color: #1a73e8; border-bottom: 3px solid #1a73e8; padding-bottom: 10px; }
    .job-card { border: 2px solid #e0e0e0; border-radius: 8px; padding: 20px; margin: 20px 0; background: #f9f9f9; }
    .job-card h2 { color: #333; margin-top: 0; }
    .company { color: #666; font-size: 18px; font-weight: bold; }
    .location { color: #888; }
    .score-high { color: #00aa00; font-size: 24px; font-weight: bold; }
    .btn { background: #1a73e8; color: white; padding: 12px 24px; text-decoration: none; border-radius: 6px; display: inline-block; margin-top: 10px; }
    .skills { margin: 10px 0; }
    .skill-tag { background: #e3f2fd; color: #1565c0; padding: 4px 8px; border-radius: 4px; margin: 2px; display: inline-block; font-size: 12px; }
    .cover-letter { background: white; padding: 15px; margin-top: 10px; border-left: 4px solid #1a73e8; white-space: pre-wrap; font-size: 14px; line-height: 1.6; }
    details { margin-top: 10px; }
    summary { cursor: pointer; font-weight: bold; color: #1a73e8; }
  </style>
</head>
<body>
  <div class="container">
    <h1>🎯 Your Daily Job Matches - ${today}</h1>
    <p>Found <strong>${jobs.length}</strong> high-match jobs for you today!</p>
    <p style="color: #666;">All cover letters are AI-generated and ready to use. Review, customize if needed, and apply!</p>
    <hr>
`;

let jobsHtml = '';

for (const item of jobs) {
  const job = item.json;
  const eval = job.ai_evaluation;

  jobsHtml += `
    <div class="job-card">
      <h2>${job.title}</h2>
      <p class="company">🏢 ${job.company}</p>
      <p class="location">📍 ${job.location}</p>
      <p class="score-high">Match Score: ${eval.match_score}/100</p>

      <p><strong>Why it matches:</strong><br>${eval.reasoning}</p>

      <div class="skills">
        <strong>✅ Matched Skills:</strong><br>
        ${eval.matched_skills.map(s => `<span class="skill-tag">${s}</span>`).join(' ')}
      </div>

      ${eval.missing_skills.length > 0 ? `
        <div class="skills">
          <strong>⚠️ Missing Skills:</strong><br>
          ${eval.missing_skills.map(s => `<span class="skill-tag">${s}</span>`).join(' ')}
        </div>
      ` : ''}

      ${eval.salary_estimate ? `<p><strong>💰 Estimated Salary:</strong> ${eval.salary_estimate}</p>` : ''}

      <details>
        <summary>📄 Your Custom Cover Letter (Click to expand)</summary>
        <div class="cover-letter">${job.cover_letter || 'Cover letter generation failed'}</div>
      </details>

      <a href="${job.url}" class="btn" target="_blank">Apply Now on ${job.source}</a>
      <p style="font-size: 12px; color: #888; margin-top: 10px;">Source: ${job.source} | Posted: ${job.posted_date}</p>
    </div>
  `;
}

const footer = `
    <hr>
    <p style="text-align: center; color: #888; font-size: 14px;">
      Job Hunting Co-Pilot • Powered by N8N & OpenAI<br>
      <em>Remember: Review and customize each application before submitting. Quality over quantity!</em>
    </p>
  </div>
</body>
</html>
`;

return [{
  json: {
    subject: `🎯 ${jobs.length} Job Match${jobs.length !== 1 ? 'es' : ''} - ${new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`,
    html: html + jobsHtml + footer,
    text: `You have ${jobs.length} high-match jobs today. View the HTML email for details.`,
    job_count: jobs.length,
    jobs: jobs.map(j => j.json)
  }
}];

